    ///   arg2 = absolute iRODS path
    ///   arg3 = AVU attribute
    ///   arg4 = AVU value
    ///   arg5 = AVU units (NULL when the AVU has no units)
    ///   arg6..arg9 unused for this entry point
    ///
    /// All `CString` allocations live for the `rcModAVUMetadata` call
